    }

    .photo-grid {
        grid-template-columns: repeat(auto-fill, minmax(150px, 1fr));
        gap: 0.625rem;
    }

    .photo-item img {
        height: 120px;
    }

    .upload-area {
        padding: 1.5rem 1rem;
    }

    .hero-section {
        padding: 1.5rem 1rem !important;
    }
}

/* Print Styles */
@media print {
    .navbar,
    footer,
    .btn,
    .alert {
        display: none !important;
    }

    body {
        font-size: 12px;
        color: #000 !important;
        background: #fff !important;
    }
}

/* Accessibility */
@media (prefers-reduced-motion: reduce) {
    * {
        animation-duration: 0.01ms !important;
        animation-iteration-count: 1 !important;
        transition-duration: 0.01ms !important;
    }
}

/* Focus Indicators - Subtle */
.btn:focus,
.form-control:focus,
.nav-link:focus {
    outline: 2px solid var(--primary-color);
    outline-offset: 1px;
}

/* Loading States */
.loading {
    opacity: 0.6;
    pointer-events: none;
}

.spinner-border-sm {
    width: 0.875rem;
    height: 0.875rem;
}

/* Text Colors - Conservative */
.text-primary { color: var(--primary-color) !important; }
.text-secondary { color: var(--secondary-color) !important; }
.text-success { color: var(--success-color) !important; }
.text-info { color: var(--info-color) !important; }
.text-warning { color: var(--warning-color) !important; }
.text-danger { color: var(--danger-color) !important; }
.text-muted { color: var(--text-muted) !important; }/* Fix for Statistics Page Visibility Issues */

/* Ensure statistics cards have proper contrast */
.card.bg-gradient h3,
.card.bg-gradient h4,
.card.bg-gradient h5,
.card.bg-gradient p,
.card.bg-gradient small {
    color: #ffffff !important;
}

/* Fix specific background colors */
.bg-primary, .bg-primary * {
    color: #ffffff !important;
}

.bg-success, .bg-success * {
    color: #ffffff !important;
}

.bg-info, .bg-info * {
    color: #ffffff !important;
}

.bg-warning, .bg-warning * {
    color: #212529 !important;
}

.bg-danger, .bg-danger * {
    color: #ffffff !important;
}

.bg-secondary, .bg-secondary * {
    color: #ffffff !important;
}

/* Ensure card text is always visible */
.card {
    background-color: #ffffff !important;
    color: #495057 !important;
}

.card-body {
    color: inherit !important;
}

/* Statistics cards specific fixes */
.stats-card h3,
.stats-card h4 {
    font-weight: 600 !important;
    margin-bottom: 0.25rem !important;
}

.stats-card p,
.stats-card small {
    opacity: 0.9;
    margin-bottom: 0 !important;
}

